      assert (a + [x])[1..] == a[1..] + [x];
    } else {
      MergeAppendS2(a[1..], s1, s2[1..], x);
      assert (a + [x])[0] == a[0];
      assert (a + [x])[1..] == a[1..] + [x];
      assert (s2 + [x])[0] == s2[0];
      assert (s2 + [x])[1..] == s2[1..] + [x];
    }
  }
}

